import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"OpenCodeDocs について | opencodedocs","description":"OpenCodeDocs を学び、AI エコシステム初のチュートリアルサイトを理解しましょう。オープンソースプロジェクトを深く解析し、ソースコード駆動で 100% 実行可能な高品質なチュートリアルを提供します。","frontmatter":{"title":"OpenCodeDocs について | opencodedocs","sidebarTitle":"プロジェクトのビジョンについて","subtitle":"OpenCodeDocs について | opencodedocs","description":"OpenCodeDocs を学び、AI エコシステム初のチュートリアルサイトを理解しましょう。オープンソースプロジェクトを深く解析し、ソースコード駆動で 100% 実行可能な高品質なチュートリアルを提供します。"},"headers":[],"relativePath":"ja/about.md","filePath":"ja/about.md"}'),n={name:"ja/about.md"};function s(i,e,c,l,d,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="opencodedocs-について" tabindex="-1">OpenCodeDocs について <a class="header-anchor" href="#opencodedocs-について" aria-label="Permalink to &quot;OpenCodeDocs について&quot;">​</a></h1><blockquote><p><strong>AI エコシステム初のチュートリアルサイト・ソースコード駆動・100% 実行可能</strong></p></blockquote><h2 id="私たちのビジョン" tabindex="-1">私たちのビジョン <a class="header-anchor" href="#私たちのビジョン" aria-label="Permalink to &quot;私たちのビジョン&quot;">​</a></h2><p>AI ツールの進化は速く、公式ドキュメントは遅れ、オンラインのチュートリアルは古くなっている——私たちはこれを変えたいと考えています。</p><p>OpenCodeDocs はオープンソースプロジェクトのソースコードと公式例を深く解析し、核心ロジックを抽出します。また、自動検証により、すべてのコードが正常に動作することを保証します。</p><p>プロジェクトが更新されると、私たちのチュートリアルも同期して更新されます。各チュートリアルには Git Commit バージョンが明記されており、どのバージョンに基づいてコードが生成されたかを確認できます。</p><p><strong>私たちの目標は、AI ツール界の「Verified Standard（検証済み標準）」になることです。</strong></p><h2 id="オープンソースライセンス" tabindex="-1">オープンソースライセンス <a class="header-anchor" href="#オープンソースライセンス" aria-label="Permalink to &quot;オープンソースライセンス&quot;">​</a></h2><p>私たちはオープンさが信頼を生むと信じています。コミュニティからの貢献、修正、補完を歓迎します。</p><h3 id="チュートリアルコンテンツ" tabindex="-1">チュートリアルコンテンツ <a class="header-anchor" href="#チュートリアルコンテンツ" aria-label="Permalink to &quot;チュートリアルコンテンツ&quot;">​</a></h3><p><strong>ライセンス</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> 表示 - 非営利 - 同一条件許諾。転載や改変が可能ですが、出典を明記し、商用目的での使用は禁止され、同じライセンスで共有する必要があります。</p><h3 id="構築ツール" tabindex="-1">構築ツール <a class="header-anchor" href="#構築ツール" aria-label="Permalink to &quot;構築ツール&quot;">​</a></h3><p><strong>VitePress</strong>: 本プロジェクトは <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> を使用して構築されています。<br> 素晴らしい静的サイトジェネレーターを提供してくれる VitePress チームに感謝します。</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">GitHub リポジトリを表示</a></p><h2 id="お問い合わせ" tabindex="-1">お問い合わせ <a class="header-anchor" href="#お問い合わせ" aria-label="Permalink to &quot;お問い合わせ&quot;">​</a></h2><ul><li><strong>メール</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const g=a(n,[["render",s]]);export{b as __pageData,g as default};
